mapper.select:
SELECT s.sponsor_seq ,s.edition_year ,s.tier_cd ,tc.com_cd_nm AS tier_cd_nm ,tc.sort_seq AS tier_sort_seq ,s.company_name ,s.logo_file_seq ,s.sort_seq ,s.use_yn ,CASE WHEN s.representative_remarks IS NOT NULL AND length(btrim(s.representative_remarks)) > 0 THEN true ELSE false END AS has_remarks ,s.description ,s.representative_remarks ,s.website_url ,cu.name AS rgst_user_name ,s.created_at AS rgst_date_time ,uu.name AS upt_user_name ,s.updated_at AS upt_date_time ,logo.logo_file_dtl_seq ,logo.logo_file_path FROM event.sponsor s LEFT JOIN event.users cu ON cu.user_seq = s.created_by LEFT JOIN event.users uu ON uu.user_seq = s.updated_by LEFT JOIN event.com_cd tc ON tc.com_cd = s.tier_cd AND tc.com_grp_cd_seq = ( SELECT com_grp_cd_seq FROM event.com_grp_cd WHERE com_grp_cd = 'SPONSOR_TIER' ) LEFT JOIN LATERAL ( SELECT (ARRAY_AGG(d.file_dtl_seq ORDER BY d.sort_seq ASC, d.file_dtl_seq ASC))[1] AS logo_file_dtl_seq ,(ARRAY_AGG(d.file_path ORDER BY d.sort_seq ASC, d.file_dtl_seq ASC))[1] AS logo_file_path FROM event.tb_file_dtl d WHERE d.file_seq = s.logo_file_seq AND d.del_yn = 'N' ) logo ON TRUE
s.deleted_at IS NULL
AND s.edition_year = #{editionYear}
AND s.tier_cd = #{tierCd}
AND s.use_yn = #{useYn}
AND s.company_name ILIKE '%' || #{keyword} || '%'
ORDER BY s.edition_year DESC, tc.sort_seq ASC NULLS LAST, s.sort_seq ASC, s.sponsor_seq DESC

mapper.update:
UPDATE event.sponsor
SET  edition_year           = #{editionYear}
    ,tier_cd                = #{tierCd}
    ,company_name           = #{companyName}
    ,logo_file_seq          = #{logoFileSeq,jdbcType=BIGINT}
    ,description            = #{description,jdbcType=VARCHAR}
    ,representative_remarks = #{representativeRemarks,jdbcType=VARCHAR}
    ,website_url            = #{websiteUrl,jdbcType=VARCHAR}
    ,sort_seq               = COALESCE(#{sortSeq,jdbcType=INTEGER}, 0)
    ,use_yn                 = COALESCE(#{useYn,jdbcType=CHAR}, use_yn)
    ,updated_by             = #{uptUserSeq,jdbcType=BIGINT}
    ,updated_at             = CURRENT_TIMESTAMP
WHERE sponsor_seq = #{sponsorSeq}
  AND deleted_at IS NULL

UPDATE event.sponsor
SET  deleted_at = CURRENT_TIMESTAMP
    ,updated_by = #{uptUserSeq,jdbcType=BIGINT}
    ,updated_at = CURRENT_TIMESTAMP
WHERE sponsor_seq = #{sponsorSeq}
  AND deleted_at IS NULL
